/* ============================================================
 * lihaocun-graph · 作品区与模态框
 * 包含：works-view / toolbar + progress / feature + poster gallery / thumb strip / modal
 * ============================================================ */

/* ---------- 作品区整体 ---------- */
.sg-works-view {
  grid-template-rows: 44px minmax(0, 1fr) 76px;
  gap: 10px;
}

/* ---------- 工具栏（分类按钮 + 进度条）---------- */

.sg-works-toolbar {
  min-width: 0;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 14px;
}

.sg-works-toolbar .sg-category-row {
  flex: 0 0 auto;
  display: flex;
  gap: 6px;
  padding: 0;
  border: 1px solid rgba(100, 135, 250, 0.14);
  border-radius: 14px;
  background: rgba(255, 255, 255, 0.78);
  box-shadow: 0 8px 20px rgba(100, 135, 250, 0.08);
}

.sg-works-toolbar .sg-category-btn {
  min-width: 92px;
  min-height: 44px;
  padding: 0 14px;
  border-radius: 12px;
  font-size: 14px;
  transition: color 0.18s ease, background 0.18s ease, transform 0.18s ease;
}

.sg-works-toolbar .sg-category-btn:active { transform: scale(0.96); }

.sg-works-progress {
  min-width: 220px;
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  align-items: center;
  gap: 7px 10px;
}

.sg-works-progress-copy {
  min-width: 0;
  overflow: hidden;
  color: var(--sg-muted);
  font-size: 12px;
  line-height: 1;
  font-weight: 720;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.sg-works-progress-count {
  color: var(--sg-primary-dark);
  font-size: 12px;
  line-height: 1;
  font-weight: 900;
}

.sg-works-progress-track {
  grid-column: 1 / -1;
  height: 5px;
  overflow: hidden;
  border-radius: 999px;
  background: rgba(100, 135, 250, 0.14);
}

.sg-works-progress-track i {
  display: block;
  width: 0;
  height: 100%;
  border-radius: inherit;
  background: linear-gradient(90deg, var(--sg-primary), #24b0a2);
  transition: width 0.3s ease;
}

/* ---------- 精选作品大卡 ---------- */

.sg-work-feature {
  position: relative;
  min-width: 0;
  min-height: 0;
  overflow: hidden;
  border: 1px solid rgba(100, 135, 250, 0.13);
  border-radius: 18px;
  display: grid;
  grid-template-rows: minmax(0, 1fr) auto;
  background: var(--sg-paper);
}

.sg-feature-poster {
  position: relative;
  min-width: 0;
  min-height: 0;
  overflow: hidden;
  isolation: isolate;
  padding: 10px 58px 8px;
  display: grid;
  place-items: center;
  background: linear-gradient(
    90deg,
    rgba(100, 135, 250, 0.14),
    rgba(232, 238, 255, 0.78) 50%,
    rgba(100, 135, 250, 0.14)
  );
}

.sg-feature-watermark {
  position: absolute;
  left: 50%;
  top: 50%;
  z-index: 0;
  max-width: 90%;
  overflow: hidden;
  color: transparent;
  font-size: 68px;
  line-height: 1;
  font-weight: 950;
  text-overflow: ellipsis;
  white-space: nowrap;
  transform: translate(-50%, -50%);
  -webkit-text-stroke: 6px rgba(100, 135, 250, 0.12);
  pointer-events: none;
}

.sg-feature-poster-gallery {
  position: relative;
  z-index: 1;
  width: min(420px, 88%);
  height: 100%;
  max-height: 188px;
}

.sg-feature-poster-card {
  position: absolute;
  left: 50%;
  top: 50%;
  width: auto;
  height: 84%;
  aspect-ratio: 2 / 3;
  overflow: hidden;
  padding: 3px;
  border: 0;
  border-radius: 12px;
  background: var(--sg-paper);
  box-shadow: 0 10px 24px rgba(30, 31, 36, 0.18);
  cursor: pointer;
  transition: transform 0.3s ease, opacity 0.3s ease;
}

.sg-feature-poster-card.sg-is-left {
  z-index: 1;
  transform: translate(-145%, -48%) rotate(-5deg);
}

.sg-feature-poster-card.sg-is-right {
  z-index: 1;
  transform: translate(45%, -48%) rotate(5deg);
}

.sg-feature-poster-card.sg-is-active {
  z-index: 3;
  height: 100%;
  padding: 4px;
  border-radius: 14px;
  opacity: 1;
  transform: translate(-50%, -50%);
  box-shadow: 0 16px 32px rgba(30, 31, 36, 0.25);
}

.sg-feature-poster-card:not(.sg-is-active):hover,
.sg-feature-poster-card:not(.sg-is-active):focus-visible {
  opacity: 1;
  filter: saturate(1.08);
}

.sg-feature-poster-card.sg-is-left:hover,
.sg-feature-poster-card.sg-is-left:focus-visible {
  transform: translate(-150%, -51%) rotate(-3deg);
}

.sg-feature-poster-card.sg-is-right:hover,
.sg-feature-poster-card.sg-is-right:focus-visible {
  transform: translate(50%, -51%) rotate(3deg);
}

.sg-feature-poster-card img {
  width: 100%;
  height: 100%;
  border-radius: 9px;
  object-fit: cover;
}

.sg-feature-poster-card:focus-visible {
  outline: 3px solid rgba(66, 104, 232, 0.68);
  outline-offset: 3px;
}

.sg-feature-status {
  position: absolute;
  right: 14px;
  top: 10px;
  z-index: 3;
  padding: 5px 8px;
  border-radius: 9px;
  color: var(--sg-ink);
  background: rgba(255, 255, 255, 0.92);
  box-shadow: 0 6px 16px rgba(30, 31, 36, 0.16);
  font-size: 12px;
  line-height: 1;
  font-weight: 820;
}

/* ---------- 精选-信息卡 ---------- */

.sg-feature-info {
  min-width: 0;
  min-height: 0;
  overflow: hidden;
  padding: 8px 58px 10px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 5px;
  text-align: center;
  background: var(--sg-paper);
  border-top: 1px solid rgba(100, 135, 250, 0.12);
}

.sg-feature-heading {
  width: 100%;
  min-width: 0;
  display: flex;
  align-items: baseline;
  justify-content: center;
  gap: 9px;
}

.sg-feature-kicker {
  color: var(--sg-primary-dark);
  font-size: 12px;
  line-height: 1;
  font-weight: 850;
}

.sg-feature-title {
  max-width: 100%;
  margin: 0;
  overflow: hidden;
  font-size: 22px;
  line-height: 1.05;
  font-weight: 950;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.sg-feature-desc {
  margin: 0;
  overflow: hidden;
  color: var(--sg-muted);
  max-width: 620px;
  font-size: 11px;
  line-height: 1.25;
  font-weight: 580;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.sg-feature-facts {
  width: 100%;
  min-width: 0;
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 0;
  border-top: 1px solid rgba(100, 135, 250, 0.13);
  border-bottom: 1px solid rgba(100, 135, 250, 0.13);
  background: rgba(100, 135, 250, 0.04);
}

.sg-feature-fact {
  min-width: 0;
  padding: 6px 8px;
  overflow: hidden;
  border-right: 1px solid rgba(100, 135, 250, 0.13);
  border-radius: 0;
  color: #596071;
  background: transparent;
  display: grid;
  gap: 3px;
}

.sg-feature-fact:last-child { border-right: 0; }

.sg-feature-fact small,
.sg-feature-fact b {
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.sg-feature-fact small {
  color: var(--sg-muted);
  font-size: 9px;
  line-height: 1;
  font-weight: 680;
}

.sg-feature-fact b {
  color: var(--sg-ink);
  font-size: 11px;
  line-height: 1.1;
  font-weight: 850;
}

.sg-feature-actions {
  position: absolute;
  right: 12px;
  top: 50%;
  z-index: 2;
  transform: translateY(-50%);
}

.sg-feature-next-button {
  width: 44px;
  min-height: 44px;
  border-radius: 50%;
  border: 3px solid rgba(255, 255, 255, 0.9);
  font-size: 24px;
  line-height: 1;
  font-weight: 880;
  color: var(--sg-paper);
  background: var(--sg-primary);
  box-shadow: 0 10px 24px rgba(42, 91, 255, 0.32);
  display: grid;
  place-items: center;
}

.sg-feature-next-button:active { transform: scale(0.94); }

/* ---------- 底部缩略条 ---------- */

.sg-work-strip-shell {
  position: relative;
  min-width: 0;
  min-height: 0;
  overflow: hidden;
  padding: 4px 0;
}

.sg-work-strip-shell::before,
.sg-work-strip-shell::after {
  content: "";
  position: absolute;
  left: 0;
  right: 0;
  z-index: 2;
  height: 2px;
  pointer-events: none;
  background: repeating-linear-gradient(
    90deg,
    rgba(100, 135, 250, 0.2),
    rgba(100, 135, 250, 0.2) 6px,
    transparent 6px,
    transparent 12px
  );
}

.sg-work-strip-shell::before { top: 0; }
.sg-work-strip-shell::after { bottom: 0; }

.sg-work-strip {
  min-width: 0;
  min-height: 0;
  height: 100%;
  overflow-x: auto;
  overflow-y: hidden;
  display: flex;
  gap: 8px;
  scroll-snap-type: x proximity;
  scrollbar-width: none;
  -webkit-overflow-scrolling: touch;
}

.sg-work-strip::-webkit-scrollbar { display: none; }

.sg-work-thumb {
  position: relative;
  flex: 0 0 126px;
  min-width: 0;
  height: 68px;
  overflow: hidden;
  border: 1px solid rgba(100, 135, 250, 0.15);
  border-radius: 13px;
  padding: 5px;
  display: grid;
  grid-template-columns: 43px minmax(0, 1fr);
  gap: 7px;
  background: rgba(255, 255, 255, 0.72);
  cursor: pointer;
  transition: transform 0.2s ease, border-color 0.2s ease, background 0.2s ease;
}

.sg-work-thumb.sg-active {
  border-color: var(--sg-primary);
  background: var(--sg-paper);
  box-shadow: inset 0 3px 0 var(--sg-primary), 0 10px 20px rgba(100, 135, 250, 0.22);
}

.sg-work-thumb:hover,
.sg-work-thumb:focus-visible {
  border-color: rgba(100, 135, 250, 0.62);
  background: var(--sg-paper);
  transform: translateY(-2px);
}

.sg-work-thumb:focus-visible {
  outline: 2px solid rgba(66, 104, 232, 0.62);
  outline-offset: 1px;
}

.sg-work-thumb:active { transform: scale(0.97); }

.sg-work-thumb-poster {
  width: 43px;
  height: 56px;
  overflow: hidden;
  border-radius: 9px;
  background: var(--sg-soft);
}

.sg-work-thumb-poster img { object-fit: cover; }

.sg-work-thumb-copy {
  min-width: 0;
  display: grid;
  gap: 5px;
}

.sg-work-thumb-title,
.sg-work-thumb-year {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.sg-work-thumb-title {
  font-size: 12px;
  line-height: 1.1;
  font-weight: 900;
}

.sg-work-thumb-year {
  color: var(--sg-muted);
  font-size: 10px;
  line-height: 1;
  font-weight: 700;
}

.sg-work-thumb-state {
  min-width: 0;
  overflow: hidden;
  color: #b64b00;
  font-size: 10px;
  line-height: 1;
  font-weight: 850;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.sg-work-thumb.sg-active .sg-work-thumb-state {
  color: var(--sg-primary-dark);
}

.sg-work-thumb.sg-visited:not(.sg-active) .sg-work-thumb-state {
  color: #287261;
}

@keyframes workHint {
  0%, 100% { border-color: rgba(100, 135, 250, 0.15); }
  50% { border-color: rgba(100, 135, 250, 0.48); }
}

.sg-work-thumb.sg-is-hint { animation: workHint 1.45s ease-in-out infinite; }

@media (prefers-reduced-motion: reduce) {
  .sg-work-thumb.sg-is-hint { animation: none; }
}

/* ---------- 模态框 ---------- */

.sg-modal {
  position: absolute;
  top: 0;
  right: 0;
  bottom: 0;
  z-index: 20;
  width: min(340px, 100%);
  display: none;
  align-items: stretch;
  justify-content: flex-end;
  padding: 12px 12px 12px 0;
  overflow: hidden;
  background: transparent;
  pointer-events: none;
}

.sg-modal.active {
  display: flex;
  pointer-events: auto;
}

.sg-modal-card {
  position: relative;
  width: 100%;
  max-height: 100%;
  border-radius: 22px;
  padding: 14px;
  display: grid;
  grid-template-rows: 119px minmax(0, 1fr);
  gap: 12px;
  overflow: auto;
}

.sg-modal-poster {
  min-width: 0;
  height: 119px;
  border-radius: 18px;
  overflow: hidden;
  background: var(--sg-soft);
}

.sg-modal-info {
  min-width: 0;
  min-height: 0;
  display: grid;
  align-content: start;
  gap: 10px;
}

.sg-modal-info strong {
  font-size: 25px;
  line-height: 1.08;
  font-weight: 820;
}

.sg-modal-info span {
  color: var(--sg-primary-dark);
  font-size: 14px;
  line-height: 1.2;
  font-weight: 720;
}

.sg-modal-info p {
  margin: 0;
  color: var(--sg-muted);
  font-size: 14px;
  line-height: 1.42;
  font-weight: 520;
}

.sg-modal-works {
  min-width: 0;
  display: grid;
  gap: 7px;
}

.sg-modal-work {
  min-width: 0;
  border-radius: 13px;
  padding: 8px 10px;
  background: rgba(100, 135, 250, 0.08);
  display: grid;
  gap: 4px;
}

.sg-modal-work b,
.sg-modal-work small {
  display: block;
  min-width: 0;
  overflow: visible;
  text-overflow: unset;
  white-space: normal;
  word-break: break-word;
}

.sg-modal-work b {
  color: var(--sg-ink);
  font-size: 14px;
  line-height: 1.15;
  font-weight: 760;
}

.sg-modal-work small {
  color: var(--sg-muted);
  font-size: 12px;
  line-height: 1.2;
  font-weight: 520;
}

.sg-modal-close {
  position: absolute;
  top: 10px;
  right: 10px;
  width: 44px;
  height: 44px;
  border-radius: 50%;
  color: var(--sg-paper);
  background: var(--sg-primary);
  border: 2px solid var(--sg-primary);
  box-shadow: 0 10px 24px rgba(100, 135, 250, 0.28);
  font-size: 28px;
  line-height: 1;
  font-weight: 900;
  z-index: 2;
}

.sg-modal-close:hover,
.sg-modal-close:focus-visible {
  color: var(--sg-paper);
  background: var(--sg-primary);
  border-color: var(--sg-primary);
}

