/* ============================================================
 * 参演作品视图
 * ============================================================ */
P._renderWorks = function () {
  var opts = this.opts;
  var works = opts.works || [];
  var view = this._els.works;
  if (!view) return;
  var categories = ['电影', '剧集'];
  var activeCat = this._activeWorkCat || '电影';
  // 分类按钮
  var catRow = el('div', 'sg-category-row', { 'aria-label': '作品类型' });
  categories.forEach(function (cat) {
    var count = works.filter(function (w) { return w.category === cat; }).length;
    var btn = el('button', 'sg-category-btn' + (cat === activeCat ? ' active' : ''), { type: 'button', 'data-cat': cat, text: cat + ' ' + count });
    catRow.appendChild(btn);
  });
  // 作品卡片网格（横滚）
  var shell = el('div', 'sg-works-shell');
  var grid = el('div', 'sg-work-grid', { 'aria-label': activeCat + '片单' });
  var filtered = works.filter(function (w) { return w.category === activeCat; });
  filtered.forEach(function (work) {
    var card = el('div', 'sg-work-card');
    card.innerHTML =
      '<div class="sg-poster"><img src="' + escapeHtml(work.poster || '') + '" alt="' + escapeHtml(work.title) + '海报"></div>' +
      '<div class="sg-work-info">' +
      '<div class="sg-work-title">' + escapeHtml(work.title) + '</div>' +
      '<div class="sg-work-role">饰 ' + escapeHtml(work.role) + '</div>' +
      '<div class="sg-work-meta">' + escapeHtml(work.release || work.year) + '</div>' +
      '<div class="sg-work-partners">' + escapeHtml(work.partners || '') + '</div>' +
      '</div>';
    grid.appendChild(card);
  });
  shell.appendChild(grid);

  view.innerHTML = '';
  view.appendChild(catRow);
  view.appendChild(shell);
};

