/* ============================================================
 * 参演作品视图（复刻 liu-haocun-0722-ts 精选大卡 + 缩略条）
 * ============================================================ */
P._renderWorks = function () {
  var self = this;
  var opts = this.opts;
  var allWorks = opts.works || [];
  var view = this._els.works;
  if (!view || !allWorks.length) return;
  var categories = ['电影', '剧集'];
  var cat = this._activeWorkCat || '电影';
  var filtered = allWorks.filter(function (w) { return w.category === cat; });
  if (!filtered.length) return;

  // 确保 activeWorkId 合法
  if (!this._activeWorkIds) this._activeWorkIds = {};
  if (!this._activePosterIndexes) this._activePosterIndexes = {};
  if (!this._visitedWorkIds) this._visitedWorkIds = {};
  if (!this._activeWorkIds[cat] || !filtered.some(function (w) { return w.id === self._activeWorkIds[cat]; })) {
    this._activeWorkIds[cat] = filtered[0].id;
  }
  var activeWork = filtered.filter(function (w) { return w.id === self._activeWorkIds[cat]; })[0] || filtered[0];
  var visitedCount = Object.keys(this._visitedWorkIds).filter(function (id) { return self._visitedWorkIds[id]; }).length;
  var progress = Math.round((visitedCount / allWorks.length) * 100);
  var progressCopy = this._worksInteracted
    ? (visitedCount === allWorks.length ? '作品图鉴已全部探索' : '下一站 · ' + (self._nextWork(cat, activeWork.id) || filtered[0]).title)
    : '选一部，看她的角色变化';

  view.innerHTML = '';

  // ----- 工具栏：分类按钮 + 进度条 -----
  var toolbar = el('div', 'sg-works-toolbar');
  var catRow = el('div', 'sg-category-row', { 'aria-label': '作品类型' });
  categories.forEach(function (c) {
    var count = allWorks.filter(function (w) { return w.category === c; }).length;
    var btn = el('button', 'sg-category-btn' + (c === cat ? ' active' : ''), {
      type: 'button', 'data-cat': c, text: c + ' ' + count
    });
    catRow.appendChild(btn);
  });
  toolbar.appendChild(catRow);

  var progressEl = el('div', 'sg-works-progress', { role: 'progressbar', 'aria-label': '作品探索进度',
    'aria-valuemin': '0', 'aria-valuemax': String(allWorks.length), 'aria-valuenow': String(visitedCount) });
  progressEl.innerHTML =
    '<span class="sg-works-progress-copy">' + escapeHtml(progressCopy) + '</span>' +
    '<b class="sg-works-progress-count">已探索 ' + visitedCount + '/' + allWorks.length + '</b>' +
    '<span class="sg-works-progress-track"><i style="width:' + progress + '%"></i></span>';
  toolbar.appendChild(progressEl);
  view.appendChild(toolbar);

  // ----- 精选作品大卡 -----
  var feature = el('article', 'sg-work-feature', { 'data-active-work': activeWork.id });

  // 海报画廊
  var posters = activeWork.posters && activeWork.posters.length ? activeWork.posters : [activeWork.poster];
  var activePosterIdx = this._activePosterIndexes[activeWork.id] || 0;
  if (!posters[activePosterIdx]) activePosterIdx = 0;
  var leftIdx = (activePosterIdx + posters.length - 1) % posters.length;
  var rightIdx = (activePosterIdx + 1) % posters.length;
  var posterEl = el('div', 'sg-feature-poster');
  posterEl.innerHTML =
    '<span class="sg-feature-watermark" aria-hidden="true">' + escapeHtml(activeWork.title) + '</span>' +
    '<div class="sg-feature-poster-gallery">' +
    (posters.length > 1
      ? ['sg-is-left', 'sg-is-active', 'sg-is-right'].map(function (posCls, i) {
          var idx = posCls === 'sg-is-active' ? activePosterIdx : posCls === 'sg-is-left' ? leftIdx : rightIdx;
          return '<button class="sg-feature-poster-card ' + posCls + '" type="button" data-select-poster="' + idx +
            '" aria-pressed="' + (posCls === 'sg-is-active' ? 'true' : 'false') + '">' +
            '<img src="' + escapeHtml(posters[idx]) + '" alt="' + escapeHtml(activeWork.title) + ' ' + (idx + 1) + '">' +
            '</button>';
        }).join('')
      : '') +
    '</div>' +
    '<span class="sg-feature-status">' + escapeHtml(activeWork.status) + '</span>';
  feature.appendChild(posterEl);

  // 信息卡
  var info = el('div', 'sg-feature-info', { 'aria-live': 'polite' });
  info.innerHTML =
    '<div class="sg-feature-heading">' +
    '<span class="sg-feature-kicker">' + escapeHtml(activeWork.release || activeWork.year) + ' · ' + escapeHtml(activeWork.category) + '</span>' +
    '<h2 class="sg-feature-title">' + escapeHtml(activeWork.title) + '</h2>' +
    '</div>' +
    '<p class="sg-feature-desc">' + escapeHtml(activeWork.desc) + '</p>' +
    '<div class="sg-feature-facts" aria-label="角色档案">' +
    '<span class="sg-feature-fact"><small>饰演角色</small><b>' + escapeHtml(activeWork.role) + '</b></span>' +
    '<span class="sg-feature-fact"><small>合作演员</small><b>' + escapeHtml(activeWork.partners || '') + '</b></span>' +
    '<span class="sg-feature-fact"><small>作品看点</small><b>' + escapeHtml(activeWork.stat) + '</b></span>' +
    '</div>' +
    '<div class="sg-feature-actions">' +
    '<button class="sg-feature-next-button" type="button" data-next-work aria-label="下一部">›</button>' +
    '</div>';
  feature.appendChild(info);

  // 分类按钮
  var nextWork = self._nextWork(cat, activeWork.id);
  if (nextWork) {
    var nextBtn = feature.querySelector('.sg-feature-next-button');
    if (nextBtn) nextBtn.setAttribute('aria-label', '下一部：' + nextWork.title);
  }

  view.appendChild(feature);

  // ----- 底部缩略条 -----
  var stripShell = el('div', 'sg-work-strip-shell');
  var strip = el('div', 'sg-work-strip', { 'aria-label': cat + '片单' });
  filtered.forEach(function (work, index) {
    var visited = Boolean(self._visitedWorkIds[work.id]);
    var isActive = work.id === activeWork.id;
    var hint = !self._worksInteracted && !isActive && index === 1;
    var btn = el('button', 'sg-work-thumb' +
      (isActive ? ' sg-active' : '') +
      (visited ? ' sg-visited' : '') +
      (hint ? ' sg-is-hint' : ''),
    { type: 'button', 'data-select-work': work.id,
      'aria-pressed': isActive ? 'true' : 'false',
      'aria-label': '查看' + work.title + (visited ? '，已探索' : '，未探索') });
    btn.innerHTML =
      '<span class="sg-work-thumb-poster"><img src="' + escapeHtml(work.poster) + '" alt=""></span>' +
      '<span class="sg-work-thumb-copy">' +
      '<span class="sg-work-thumb-title">' + escapeHtml(work.title) + '</span>' +
      '<span class="sg-work-thumb-year">' + escapeHtml(work.release || work.year) + '</span>' +
      '<span class="sg-work-thumb-state">' + (isActive ? '正在看' : visited ? '饰 ' + escapeHtml(work.role.split(/[\/／]/)[0].trim()) : '看她演谁') + '</span>' +
      '</span>';
    strip.appendChild(btn);
  });
  stripShell.appendChild(strip);
  view.appendChild(stripShell);
};

P._nextWork = function (cat, currentId) {
  var filtered = (this.opts.works || []).filter(function (w) { return w.category === cat; });
  var idx = filtered.map(function (w) { return w.id; }).indexOf(currentId);
  return idx >= 0 ? filtered[(idx + 1) % filtered.length] : filtered[0];
};

