// 参演作品：分类按钮 / 缩略条 / 下一部 / 海报切换
on(this._els.works, 'click', function (event) {
  var catBtn = event.target.closest('.sg-category-btn');
  if (catBtn) {
    self._activeWorkCat = catBtn.getAttribute('data-cat');
    self._renderWorks();
    return;
  }
  var thumbBtn = event.target.closest('[data-select-work]');
  if (thumbBtn) {
    var wid = thumbBtn.getAttribute('data-select-work');
    var work = (self.opts.works || []).filter(function (w) { return w.id === wid; })[0];
    if (work) {
      if (!self._activeWorkIds) self._activeWorkIds = {};
      self._activeWorkCat = work.category;
      self._activeWorkIds[work.category] = work.id;
      if (!self._visitedWorkIds) self._visitedWorkIds = {};
      self._visitedWorkIds[work.id] = true;
      self._worksInteracted = true;
    }
    self._renderWorks();
    return;
  }
  var nextBtn = event.target.closest('[data-next-work]');
  if (nextBtn) {
    var activeFeature = self._els.works.querySelector('[data-active-work]');
    if (activeFeature) {
      var wid2 = activeFeature.getAttribute('data-active-work');
      var next = self._nextWork(self._activeWorkCat, wid2);
      if (next) {
        if (!self._visitedWorkIds) self._visitedWorkIds = {};
        self._visitedWorkIds[wid2] = true;
        self._worksInteracted = true;
        if (!self._activeWorkIds) self._activeWorkIds = {};
        self._activeWorkIds[self._activeWorkCat] = next.id;
        self._renderWorks();
      }
    }
    return;
  }
  var posterBtn = event.target.closest('[data-select-poster]');
  if (posterBtn) {
    var pidx = Number(posterBtn.getAttribute('data-select-poster')) || 0;
    var activeFeature2 = self._els.works.querySelector('[data-active-work]');
    if (activeFeature2) {
      var workId = activeFeature2.getAttribute('data-active-work');
      if (!self._activePosterIndexes) self._activePosterIndexes = {};
      self._activePosterIndexes[workId] = pidx;
      if (!self._visitedWorkIds) self._visitedWorkIds = {};
      self._visitedWorkIds[workId] = true;
      self._worksInteracted = true;
      self._renderWorks();
    }
  }
});
